13	
14	  const neighbors: Cell[] = liveCells.flatMap(([x, y]) =>
15	    NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy])
16	  );
17	
18	  const counts = new Map<string, number>();
19	  const candidates = new Map<string, Cell>();
20	  for (const cell of neighbors) {
21	    const k = cellKey(cell);
22	    counts.set(k, (counts.get(k) ?? 0) + 1);
23	    candidates.set(k, cell);
24	  }
25	
26	  const survives = (k: string, count: number): boolean =>
27	    count === 3 || (count === 2 && live.has(k));
